GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA quote TO web_anon;

-- Schema: quote_qa
CREATE SCHEMA IF NOT EXISTS quote_qa;

CREATE OR REPLACE FUNCTION quote_qa.clean()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
  RETURN 'quote_qa.clean: all quote data removed';
END;
$function$;
COMMENT ON FUNCTION quote_qa.clean() IS 'Clean all quote demo data';

CREATE OR REPLACE FUNCTION quote_qa.seed()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client1 int;
  v_client2 int;
  v_client3 int;
  v_d1 int;
  v_d2 int;
  v_d3 int;
  v_f1 int;
  v_f2 int;
BEGIN
  -- Set tenant context for RLS
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Cleanup
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  -- Récupérer des clients (CRM QA doit avoir tourné)
  SELECT id INTO v_client1 FROM crm.client ORDER BY id LIMIT 1;
  SELECT id INTO v_client2 FROM crm.client ORDER BY id LIMIT 1 OFFSET 1;
  SELECT id INTO v_client3 FROM crm.client ORDER BY id LIMIT 1 OFFSET 2;
  IF v_client3 IS NULL THEN v_client3 := v_client1; END IF;
  IF v_client2 IS NULL THEN v_client2 := v_client1; END IF;

  -- Devis 1: brouillon
  PERFORM quote.post_devis_save(jsonb_build_object(
    'client_id', v_client1, 'objet', 'Rénovation cuisine',
    'validite_jours', 30, 'notes', 'Devis préliminaire, à confirmer après visite.'
  ));
  SELECT id INTO v_d1 FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d1, 'description', 'Dépose anciens meubles', 'quantite', 1, 'unite', 'forfait', 'prix_unitaire', 250, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d1, 'description', 'Pose nouveaux meubles', 'quantite', 12, 'unite', 'h', 'prix_unitaire', 45, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d1, 'description', 'Crédence carrelage', 'quantite', 3.5, 'unite', 'm2', 'prix_unitaire', 65, 'tva_rate', 20));

  -- Devis 2: envoyé
  PERFORM quote.post_devis_save(jsonb_build_object(
    'client_id', v_client2, 'objet', 'Peinture salon + chambre',
    'validite_jours', 45
  ));
  SELECT id INTO v_d2 FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d2, 'description', 'Préparation murs (enduit + ponçage)', 'quantite', 55, 'unite', 'm2', 'prix_unitaire', 12, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d2, 'description', 'Peinture 2 couches', 'quantite', 55, 'unite', 'm2', 'prix_unitaire', 18, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d2, 'description', 'Fourniture peinture', 'quantite', 6, 'unite', 'u', 'prix_unitaire', 42, 'tva_rate', 20));

  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_d2));

  -- Devis 3: accepté
  PERFORM quote.post_devis_save(jsonb_build_object(
    'client_id', v_client3, 'objet', 'Installation plomberie salle de bain',
    'validite_jours', 30, 'notes', 'Accès chantier : code 4521B'
  ));
  SELECT id INTO v_d3 FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d3, 'description', 'Dépose sanitaires existants', 'quantite', 4, 'unite', 'h', 'prix_unitaire', 45, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d3, 'description', 'Tuyauterie cuivre', 'quantite', 8, 'unite', 'm', 'prix_unitaire', 28, 'tva_rate', 20));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d3, 'description', 'Pose douche italienne', 'quantite', 1, 'unite', 'forfait', 'prix_unitaire', 850, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_d3, 'description', 'Robinetterie', 'quantite', 3, 'unite', 'u', 'prix_unitaire', 120, 'tva_rate', 20));

  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_d3));
  PERFORM quote.post_devis_accepter(jsonb_build_object('id', v_d3));

  -- Facture 1: envoyée (depuis devis 3)
  PERFORM quote.post_devis_facturer(jsonb_build_object('id', v_d3));
  SELECT id INTO v_f1 FROM quote.facture WHERE devis_id = v_d3;
  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_f1));

  -- Facture 2: payée (directe)
  PERFORM quote.post_facture_save(jsonb_build_object(
    'client_id', v_client1, 'objet', 'Dépannage fuite robinet',
    'notes', 'Intervention urgente samedi matin'
  ));
  SELECT id INTO v_f2 FROM quote.facture WHERE devis_id IS NULL ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object('facture_id', v_f2, 'description', 'Déplacement', 'quantite', 1, 'unite', 'forfait', 'prix_unitaire', 50, 'tva_rate', 20));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('facture_id', v_f2, 'description', 'Main oeuvre', 'quantite', 1.5, 'unite', 'h', 'prix_unitaire', 55, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('facture_id', v_f2, 'description', 'Joint + raccord', 'quantite', 1, 'unite', 'u', 'prix_unitaire', 15, 'tva_rate', 20));

  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_f2));
  PERFORM quote.post_facture_payer(jsonb_build_object('id', v_f2));

  RETURN 'quote_qa.seed: 3 devis (brouillon/envoyé/accepté) + 2 factures (envoyée/payée) + lignes variées';
END;
$function$;
COMMENT ON FUNCTION quote_qa.seed() IS 'QA seed : données de démonstration réalistes';

GRANT USAGE ON SCHEMA quote_qa TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA quote_qa TO web_anon;
